import React from 'react';
import { BarChart3, Radio, Globe, Bell } from 'lucide-react';
import { useTranslation } from '../../i18n/context';

interface StatsOverviewProps {
  stats: {
    aeoScore: number | null;
    citationCount: number;
    languagesAnalyzed: number;
    activeAlerts: number;
  };
}

const StatsOverview: React.FC<StatsOverviewProps> = ({ stats }) => {
  const { t } = useTranslation();

  const cards = [
    {
      key: 'aeoScore' as const,
      label: t.dashboard.aeoScore,
      suffix: '/100',
      icon: BarChart3,
      iconBg: 'bg-blue-500/10',
      iconColor: 'text-blue-400',
    },
    {
      key: 'citationCount' as const,
      label: t.dashboard.citations,
      suffix: '',
      icon: Radio,
      iconBg: 'bg-emerald-500/10',
      iconColor: 'text-emerald-400',
    },
    {
      key: 'languagesAnalyzed' as const,
      label: t.dashboard.languages,
      suffix: '/10',
      icon: Globe,
      iconBg: 'bg-purple-500/10',
      iconColor: 'text-purple-400',
    },
    {
      key: 'activeAlerts' as const,
      label: t.dashboard.alerts,
      suffix: '',
      icon: Bell,
      iconBg: 'bg-amber-500/10',
      iconColor: 'text-amber-400',
    },
  ];

  const hasData = stats.aeoScore !== null || stats.citationCount > 0 || stats.languagesAnalyzed > 0 || stats.activeAlerts > 0;

  return (
    <div>
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
        {cards.map((card) => {
          const Icon = card.icon;
          const value = stats[card.key];
          const isNull = value === null || value === undefined;

          return (
            <div
              key={card.key}
              className="relative bg-white/[0.03] border border-white/[0.06] rounded-xl p-5 hover:bg-white/[0.05] hover:border-white/[0.08] transition-all duration-200"
            >
              <p className="text-[12px] uppercase tracking-wider text-zinc-500 font-medium">
                {card.label}
              </p>
              <div className="flex items-baseline mt-2">
                {isNull ? (
                  <div>
                    <span className="text-2xl font-bold text-zinc-600 tracking-tight">&mdash;</span>
                    <p className="text-[12px] text-zinc-600 mt-1">{t.analysis.noAuditYet}</p>
                  </div>
                ) : (
                  <>
                    <span className="text-2xl font-bold text-white tracking-tight">{value}</span>
                    {card.suffix && (
                      <span className="text-lg text-zinc-500 font-normal">{card.suffix}</span>
                    )}
                  </>
                )}
              </div>
              <div className={`absolute top-4 right-4 w-8 h-8 rounded-lg ${card.iconBg} flex items-center justify-center`}>
                <Icon className={`w-4 h-4 ${card.iconColor}`} />
              </div>
            </div>
          );
        })}
      </div>

      {!hasData && (
        <p className="text-zinc-500 text-[14px] text-center py-4">
          {t.dashboard.noDataYet}
        </p>
      )}
    </div>
  );
};

export default StatsOverview;

import React from 'react';
import { Search, Radio, Globe } from 'lucide-react';
import { useTranslation } from '../../i18n/context';

interface QuickActionsProps {
  credits: number;
  onNavigate: (page: string) => void;
}

const QuickActions: React.FC<QuickActionsProps> = ({ credits, onNavigate }) => {
  const { t } = useTranslation();

  const actions = [
    {
      icon: Search,
      iconBg: 'bg-blue-500/10',
      iconColor: 'text-blue-400',
      title: t.dashboard.newAuditAction,
      description: t.dashboard.newAuditDesc,
      cost: `1 ${t.dashboard.creditCost} ⚡`,
      cta: `${t.dashboard.launch} →`,
      ctaColor: 'text-blue-400 group-hover:text-blue-300',
      page: 'new-analysis',
    },
    {
      icon: Radio,
      iconBg: 'bg-emerald-500/10',
      iconColor: 'text-emerald-400',
      title: t.dashboard.checkCitations,
      description: t.dashboard.checkCitationsDesc,
      cost: `2 ${t.dashboard.creditsCostLabel} ⚡`,
      cta: `${t.dashboard.check} →`,
      ctaColor: 'text-emerald-400 group-hover:text-emerald-300',
      page: 'ai-monitoring',
    },
    {
      icon: Globe,
      iconBg: 'bg-purple-500/10',
      iconColor: 'text-purple-400',
      title: t.dashboard.multilingualAction,
      description: t.dashboard.multilingualDesc,
      cost: `3 ${t.dashboard.creditsCostLabel} ⚡ ${t.dashboard.perLanguage}`,
      cta: `${t.dashboard.analyze} →`,
      ctaColor: 'text-purple-400 group-hover:text-purple-300',
      page: 'multilingual',
    },
  ];

  return (
    <div>
      <h2 className="text-xl font-semibold text-white">{t.dashboard.quickActions}</h2>
      <p className="text-[14px] text-zinc-400 mt-1">{t.dashboard.startHere}</p>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-5 mt-6">
        {actions.map((action) => {
          const Icon = action.icon;
          return (
            <button
              key={action.page}
              onClick={() => onNavigate(action.page)}
              className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-6 hover:bg-white/[0.05] hover:border-white/[0.08] transition-all duration-200 cursor-pointer group text-left"
            >
              <div className={`w-10 h-10 rounded-xl ${action.iconBg} flex items-center justify-center mb-4`}>
                <Icon className={`w-5 h-5 ${action.iconColor}`} />
              </div>
              <h3 className="text-white font-semibold">{action.title}</h3>
              <p className="text-[14px] text-zinc-400 mt-2 leading-relaxed">{action.description}</p>
              <p className="mt-4 text-[13px] font-mono text-amber-400">{action.cost}</p>
              <p className={`mt-3 text-[14px] font-medium ${action.ctaColor} transition-all duration-150`}>
                <span className="inline-block group-hover:translate-x-1 transition-transform duration-150">
                  {action.cta}
                </span>
              </p>
            </button>
          );
        })}
      </div>
    </div>
  );
};

export default QuickActions;

